Here are pytest-style unit tests in plain text (no markdown formatting). You can copy this directly into a test file such as test_is_business_hours.py.

from datetime import datetime
from your_module import is_business_hours

def test_happy_path_middle_of_business_day():
    dt = datetime(2024, 5, 1, 10, 0)  # Wednesday, 10 AM
    assert is_business_hours(dt) is True

def test_edge_case_start_of_business_hours():
    dt = datetime(2024, 5, 1, 9, 0)  # Exactly 9 AM
    assert is_business_hours(dt) is True

def test_edge_case_end_of_business_hours():
    dt = datetime(2024, 5, 1, 17, 0)  # Exactly 5 PM
    assert is_business_hours(dt) is False  # End is exclusive

def test_before_business_hours():
    dt = datetime(2024, 5, 1, 8, 59)
    assert is_business_hours(dt) is False

def test_after_business_hours():
    dt = datetime(2024, 5, 1, 17, 1)
    assert is_business_hours(dt) is False

def test_weekend_saturday():
    dt = datetime(2024, 5, 4, 12, 0)  # Saturday
    assert is_business_hours(dt) is False

def test_weekend_sunday():
    dt = datetime(2024, 5, 5, 12, 0)  # Sunday
    assert is_business_hours(dt) is False

def test_default_uses_now(monkeypatch):
    fake_now = datetime(2024, 5, 1, 11, 0)  # Wednesday 11 AM
    monkeypatch.setattr("your_module.datetime", type("FakeDateTime", (), {
        "now": staticmethod(lambda: fake_now),
        "weekday": datetime.weekday,
    }))
    assert is_business_hours() is True

def test_invalid_input_type():
    try:
        is_business_hours("not a datetime")
        assert False, "Expected TypeError"
    except TypeError:
        assert True

